from collections import Counter

def get_mode(data):
    if not data: return []
    counts = Counter(data)
    max_count = max(counts.values())
    return sorted(val for val, count in counts.items() if count == max_count)

if __name__ == "__main__":
    print(f"Mode of [1, 1, 2, 2]: {get_mode([1, 1, 2, 2])}")
